import {getNextWrappingIndex, getNextNonDisabledIndex} from '../../utils'
import {getHighlightedIndexOnOpen, getDefaultValue} from '../utils'
import commonReducer from '../reducer'
import {getItemIndexByCharacterKey} from './utils'
